// Generates public/media-config.js from an env var so the self-contained docs viewer can load
// big media (videos + GIFs) from a Cloudflare R2 bucket without the URL being hardcoded/committed.
// Everything under public/ is served verbatim, so we materialize a tiny JS file the viewer loads
// at runtime.
//
// Env: DOCS_MEDIA_BASE = https://pub-<hash>.r2.dev   (no trailing slash)
// Unset/empty -> viewer falls back to serving media locally from ./media/.
//
// Runs on `predev` and `build`. The generated file is gitignored.

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const docsRoot = join(dirname(fileURLToPath(import.meta.url)), "..");

// Minimal .env loader — this package has no dependencies on purpose. Real env wins.
function loadEnvFile(file) {
  if (!existsSync(file)) return;
  for (const line of readFileSync(file, "utf8").split("\n")) {
    if (line.trimStart().startsWith("#")) continue;
    const m = line.match(/^\s*([\w.-]+)\s*=\s*(.*?)\s*$/);
    if (!m || process.env[m[1]] !== undefined) continue;
    process.env[m[1]] = m[2].replace(/^(['"])(.*)\1$/, "$2");
  }
}
loadEnvFile(join(docsRoot, ".env.local"));
loadEnvFile(join(docsRoot, ".env"));

const base = (process.env.DOCS_MEDIA_BASE || "").trim().replace(/\/+$/, "");
const out = join(docsRoot, "public", "media-config.js");

writeFileSync(
  out,
  `// AUTO-GENERATED by scripts/gen-media-config.mjs — do not edit, do not commit.\n` +
    `window.DOCS_MEDIA_BASE = ${JSON.stringify(base)};\n`
);

console.log(`[docs] media base -> ${base || "(local ./media/)"}`);
